/**
 * Curated system-design practice questions, grouped by track.
 *
 * Keep prompts short and self-contained. The user can still elaborate before
 * starting a session. Requirements are generated by the LLM (same flow as
 * custom prompts), so we don't pre-bake them here.
 */

export type QuestionCategory = "backend" | "android" | "ios";

export type BankQuestion = {
  id: string;
  category: QuestionCategory;
  title: string;
  prompt: string;
  difficulty: "easy" | "medium" | "hard";
  tags?: string[];
};

export const CATEGORY_LABEL: Record<QuestionCategory, string> = {
  backend: "Backend",
  android: "Mobile · Android",
  ios: "Mobile · iOS",
};

