export const QUESTION_BANK: BankQuestion[] = [...BACKEND, ...ANDROID, ...IOS];

export function getQuestionsByCategory(category: QuestionCategory): BankQuestion[] {
  return QUESTION_BANK.filter((q) => q.category === category);
}

export function getQuestionById(id: string): BankQuestion | undefined {
  return QUESTION_BANK.find((q) => q.id === id);
}
